import 'package:flutter/material.dart';
import '../widgets/custom_button.dart';
import '../widgets/custom_textfield.dart';
import '../mock/dados_mock.dart';

class CadastroScreen extends StatelessWidget {
  final TextEditingController nomeCtrl = TextEditingController();
  final TextEditingController idadeCtrl = TextEditingController();
  final TextEditingController pesoCtrl = TextEditingController();
  final TextEditingController alturaCtrl = TextEditingController();
  final TextEditingController objetivoCtrl = TextEditingController();

  CadastroScreen({super.key});

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text("Cadastro de Usuário"), backgroundColor: Colors.teal),
      body: SingleChildScrollView(
        padding: const EdgeInsets.all(24.0),
        child: Column(
          children: [
            CustomTextField(label: "Nome Completo", controller: nomeCtrl),
            CustomTextField(label: "Idade", controller: idadeCtrl, keyboardType: TextInputType.number),
            CustomTextField(label: "Peso (kg)", controller: pesoCtrl, keyboardType: TextInputType.number),
            CustomTextField(label: "Altura (m)", controller: alturaCtrl, keyboardType: TextInputType.number),
            CustomTextField(label: "Objetivo Fitness", controller: objetivoCtrl),
            const SizedBox(height: 20),
            CustomButton(
              texto: "Salvar Perfil",
              onPressed: () {

                if (nomeCtrl.text.isNotEmpty) {
                  DadosMock.usuarioAtual.nome = nomeCtrl.text;
                  DadosMock.usuarioAtual.objetivo = objetivoCtrl.text;
                }
                Navigator.pop(context);
              },
            ),
          ],
        ),
      ),
    );
  }
}

import 'package:flutter/material.dart';
import '../mock/dados_mock.dart';
import 'treino_screen.dart';
import 'alimentacao_screen.dart';
import 'perfil_screen.dart';
import 'metas_screen.dart';

class HomeScreen extends StatelessWidget {
  const HomeScreen({super.key});

  @override
  Widget build(BuildContext context) {
    final usuario = DadosMock.usuarioAtual;

    return Scaffold(
      appBar: AppBar(
        title: const Text("FitLife Dashboard"),
        backgroundColor: Colors.teal,
      ),
      body: Padding(
        padding: const EdgeInsets.all(16.0),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Text("Olá, ${usuario.nome}!", style: const TextStyle(fontSize: 24, fontWeight: FontWeight.bold)),
            const SizedBox(height: 10),
            Card(
              color: Colors.teal.shade50,
              child: Padding(
                padding: const EdgeInsets.all(16.0),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.stretch,
                  children: [
                    const Text("Resumo da Evolução", style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold)),
                    const SizedBox(height: 8),
                    Text("Objetivo Atual: ${usuario.objetivo}"),
                    Text("Peso Registrado: ${usuario.peso} kg"),
                  ],
                ),
              ),
            ),
            const SizedBox(height: 20),
            const Text("Navegação Rápida", style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold)),
            const SizedBox(height: 10),
            Expanded(
              child: GridView.count(
                crossAxisCount: 2,
                crossAxisSpacing: 10,
                mainAxisSpacing: 10,
                children: [
                  _buildNavButton(context, Icons.fitness_center, "Treinos", const TreinoScreen()),
                  _buildNavButton(context, Icons.restaurant_menu, "Alimentação", const AlimentacaoScreen()),
                  _buildNavButton(context, Icons.flag, "Metas & Evolução", const MetasScreen()),
                  _buildNavButton(context, Icons.person, "Perfil", const PerfilScreen()),
                ],
              ),
            )
          ],
        ),
      ),
    );
  }

  Widget _buildNavButton(BuildContext context, IconData icon, String title, Widget screen) {
    return ElevatedButton(
      style: ElevatedButton.styleFrom(
        backgroundColor: Colors.white,
        foregroundColor: Colors.teal,
        elevation: 2,
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(15)),
      ),
      onPressed: () => Navigator.push(context, MaterialPageRoute(builder: (_) => screen)),
      child: Column(
        mainAxisAlignment: MainAxisAlignment.center,
        children: [
          Icon(icon, size: 40),
          const SizedBox(height: 10),
          Text(title, textAlign: TextAlign.center, style: const TextStyle(fontSize: 16, fontWeight: FontWeight.bold)),
        ],
      ),
    );
  }
}

import 'package:flutter/material.dart';
import '../mock/dados_mock.dart';

class MetasScreen extends StatefulWidget {
  const MetasScreen({super.key});

  @override
  State<MetasScreen> createState() => _MetasScreenState();
}

class _MetasScreenState extends State<MetasScreen> {

  final Map<String, bool> _metasStatus = {
    for (var item in DadosMock.metas) item: false
  };

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text("Metas e Evolução"), backgroundColor: Colors.teal),
      body: SingleChildScrollView(
        padding: const EdgeInsets.all(16.0),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            const Text("Histórico de Peso Corporal", style: TextStyle(fontSize: 20, fontWeight: FontWeight.bold, color: Colors.teal)),
            const SizedBox(height: 10),
            Card(
              child: ListView.builder(
                shrinkWrap: true,
                physics: const NeverScrollableScrollPhysics(),
                itemCount: DadosMock.historicoPesos.length,
                itemBuilder: (context, index) {
                  return ListTile(
                    leading: const Icon(Icons.timeline, color: Colors.teal),
                    title: Text("Registro #${DadosMock.historicoPesos.length - index}"),
                    trailing: Text(DadosMock.historicoPesos[index], style: const TextStyle(fontWeight: FontWeight.bold)),
                  );
                },
              ),
            ),
            const SizedBox(height: 30),
            const Text("Metas Fitness Pessoais", style: TextStyle(fontSize: 20, fontWeight: FontWeight.bold, color: Colors.teal)),
            const SizedBox(height: 10),
            Card(
              child: Column(
                children: _metasStatus.keys.map((meta) {
                  return CheckboxListTile(
                    activeColor: Colors.teal,
                    title: Text(meta, style: TextStyle(decoration: _metasStatus[meta]! ? TextDecoration.lineThrough : null)),
                    value: _metasStatus[meta],
                    onChanged: (bool? value) {
                      setState(() {
                        _metasStatus[meta] = value ?? false;
                      });
                    },
                  );
                }).toList(),
              ),
            )
          ],
        ),
      ),
    );
  }
}

