import 'package:flutter/material.dart';
import '../mock/dados_mock.dart';
import '../widgets/treino_card.dart';

class TreinoScreen extends StatelessWidget {
  const TreinoScreen({super.key});

  @override
  Widget build(BuildContext context) {
    return DefaultTabController(
      length: 4,
      child: Scaffold(
        appBar: AppBar(
          title: const Text("Lista de Treinos"),
          backgroundColor: Colors.teal,
          bottom: const TabBar(
            indicatorColor: Colors.white,
            tabs: [
              Tab(text: "Peito"),
              Tab(text: "Pernas"),
              Tab(text: "Costas"),
              Tab(text: "Braços"),
            ],
          ),
        ),
        body: TabBarView(
          children: [
            _buildListaPorCategoria("Peito"),
            _buildListaPorCategoria("Pernas"),
            _buildListaPorCategoria("Costas"),
            _buildListaPorCategoria("Braços"),
          ],
        ),
      ),
    );
  }

  Widget _buildListaPorCategoria(String categoria) {
    final filtrados = DadosMock.treinos.where((t) => t.grupoMuscular == categoria).toList();
    return ListView.builder(
      itemCount: filtrados.length,
      itemBuilder: (context, index) {
        return TreinoCard(treino: filtrados[index]);
      },
    );
  }
}

class AuthService {
  // Simula um login validando e-mail e senha
  bool login(String email, String senha) {
    if (email.isNotEmpty && senha.isNotEmpty) {
      return true;
    }
    return false;
  }
}

import 'package:flutter/material.dart';

class CustomButton extends StatelessWidget {
  final String texto;
  final VoidCallback onPressed;

  const CustomButton({super.key, required this.texto, required this.onPressed});

  @override
  Widget build(BuildContext context) {
    return SizedBox(
      width: double.infinity,
      height: 50,
      child: ElevatedButton(
        style: ElevatedButton.styleFrom(
          backgroundColor: Colors.teal,
          shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
        ),
        onPressed: onPressed,
        child: Text(texto, style: const TextStyle(fontSize: 18, color: Colors.white)),
      ),
    );
  }
}

import 'package:flutter/material.dart';

class CustomTextField extends StatelessWidget {
  final String label;
  final bool isPassword;
  final TextEditingController? controller;
  final TextInputType keyboardType;

  const CustomTextField({
    super.key,
    required this.label,
    this.isPassword = false,
    this.controller,
    this.keyboardType = TextInputType.text,
  });

  @override
  Widget build(BuildContext context) {
    return Padding(
      padding: const EdgeInsets.only(bottom: 16.0),
      child: TextField(
        controller: controller,
        obscureText: isPassword,
        keyboardType: keyboardType,
        decoration: InputDecoration(
          labelText: label,
          border: OutlineInputBorder(borderRadius: BorderRadius.circular(10)),
          focusedBorder: const OutlineInputBorder(
            borderSide: BorderSide(color: Colors.teal),
          ),
        ),
      ),
    );
  }
}

